#!/usr/bin/env bash
# ship-newquiz-redesign.sh
# Replaces the NewQuizModal emoji/cheap-icons design with proper SVG icons,
# adds a goal picker row, strips em-dashes, fixes the API fallback URL, and
# lands CLAUDE.md with the project-wide "no emoji, no em-dash" rule.
#
# Usage (from your Mac, inside the squarespell repo root):
#   bash _cherry-pick-to-main/ship-newquiz-redesign.sh
#
# The script is idempotent; safe to rerun if the first run fails.
set -euo pipefail

BRANCH="fix/newquiz-modal-redesign-20260414"
REPO_ROOT="$(pwd)"

echo "==> cwd: $REPO_ROOT"
if [ ! -d "frontend/app/dashboard/quizzes/_components" ]; then
  echo "ERROR: frontend/app/dashboard/quizzes/_components not found."
  echo "Are you in the squarespell repo root?"
  exit 1
fi

echo "==> Fetching origin/main"
git fetch origin main

echo "==> Creating fresh branch $BRANCH from origin/main"
git checkout -B "$BRANCH" origin/main

echo "==> Writing NewQuizModal.tsx"
cat > frontend/app/dashboard/quizzes/_components/NewQuizModal.tsx.b64 <<B64MODAL_EOF

B64MODAL_EOF
base64 -d frontend/app/dashboard/quizzes/_components/NewQuizModal.tsx.b64 > frontend/app/dashboard/quizzes/_components/NewQuizModal.tsx
rm frontend/app/dashboard/quizzes/_components/NewQuizModal.tsx.b64

echo "==> Writing quizTemplates.ts"
cat > frontend/app/dashboard/quizzes/_components/quizTemplates.ts.b64 <<B64TPL_EOF

B64TPL_EOF
base64 -d frontend/app/dashboard/quizzes/_components/quizTemplates.ts.b64 > frontend/app/dashboard/quizzes/_components/quizTemplates.ts
rm frontend/app/dashboard/quizzes/_components/quizTemplates.ts.b64

echo "==> Writing quizzes/page.tsx (strip em-dash from header comment)"
cat > frontend/app/dashboard/quizzes/page.tsx.b64 <<B64QP_EOF

B64QP_EOF
base64 -d frontend/app/dashboard/quizzes/page.tsx.b64 > frontend/app/dashboard/quizzes/page.tsx
rm frontend/app/dashboard/quizzes/page.tsx.b64

echo "==> Writing CLAUDE.md (project rules)"
cat > CLAUDE.md.b64 <<B64CLAUDE_EOF

B64CLAUDE_EOF
base64 -d CLAUDE.md.b64 > CLAUDE.md
rm CLAUDE.md.b64

echo "==> Staging"
git add frontend/app/dashboard/quizzes/_components/NewQuizModal.tsx
git add frontend/app/dashboard/quizzes/_components/quizTemplates.ts
git add frontend/app/dashboard/quizzes/page.tsx
git add CLAUDE.md

echo "==> Committing"
git commit -m "fix(frontend): redesign NewQuizModal with SVG icons, goal picker, no em-dashes

- Replaces 6 emoji template icons with inline SVGs on colored tiles
- Adds 4-option goal picker (Capture leads, Recommend, Score/segment, Grow email)
- Repoints API fallback from squarespell-backend to squarespell-api
- Improves 404 error surface with actionable message
- Strips em-dashes across all modified files
- Adds CLAUDE.md with project-wide no-emoji / no-em-dash rules

Goal choice is packed into the existing topic field so the backend
from-url route keeps its current contract. Template and topic are
optional. Blank path preserved.

🤖 Generated with [Claude Code](https://claude.com/claude-code)

Co-Authored-By: Claude Opus 4.6 <noreply@anthropic.com>"

echo "==> Pushing"
git push -u origin "$BRANCH"

echo ""
echo "==> Done. Open a PR at:"
echo "    https://github.com/Squarespell/squarespell/pull/new/$BRANCH"
echo ""
